import { AttachInternals, Component, Element, EventEmitter, Prop, h, Event, State, Listen, Watch, Host } from '@stencil/core';
import {
  DualComboboxLocation,
  DualComboboxActiveInput,
  DualComboboxItemElement,
  DualComboboxValueItem,
  isDualComboboxItemElement,
  DualComboboxFilterMode,
  DualComboboxIconNameType,
} from './wdpr-dual-combobox.model';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { generateRandId } from '../../utils/utils';
import { findNextEnabledIndex, getInitialFocusIndex, itemMatchesFilter, splitLabel } from './wdpr-dual-combobox.utils';
import { RadialLabelPlacement, RadialLoaderSize } from '../wdpr-radial-loader/wdpr-radial-loader.model';
import { InlineMessageSize } from '../wdpr-inline-message/wdpr-inline-message.model';
import { DualTextFieldRequirementIndicator } from '../wdpr-dual-text-field/wdpr-dual-text-field.model';

@Component({
  tag: 'wdpr-dual-combobox',
  scoped: true,
  styleUrl: 'wdpr-dual-combobox.css',
  formAssociated: true,
})
export class WdprDualCombobox {
  private _listId: string;
  private _slotObserver: MutationObserver;
  private _listEl: HTMLDivElement | null = null;
  private _cachedItems: DualComboboxItemElement[] | null = null;
  private _measureDebounceTimer: ReturnType<typeof setTimeout>;

  @Element() el: HTMLWdprDualComboboxElement;

  @AttachInternals() internals: ElementInternals;

  @State() _activeInput: DualComboboxActiveInput = null;
  @State() _leadingInputValue = '';
  @State() _trailingInputValue = '';
  @State() _expanded = false;
  @State() _readyToShow: boolean = false;
  @State() _focusedIndex: number = -1;
  @State() _measuredMaxHeight: string | null = null;
  @State() _activeDescendantId?: string = undefined;
  @State() _selectedValue: DualComboboxValueItem | null = null;

  @Prop({ reflect: true }) leadingValue: string = '';
  @Prop() leadingLabel: string = '';
  @Prop() leadingRequirementIndicator: DualTextFieldRequirementIndicator = 'none';
  @Prop({ reflect: true }) trailingValue: string = '';
  @Prop() trailingLabel: string = '';
  @Prop() trailingRequirementIndicator: DualTextFieldRequirementIndicator = 'none';

  @Prop() helperText: string = '';
  @Prop() disabled: boolean = false;
  @Prop() required: boolean = false;
  @Prop() error: boolean = false;
  @Prop() readonly: boolean = false;
  @Prop() name?: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel!: string;
  @Prop() filterMode: DualComboboxFilterMode = 'auto';

  @Prop({ reflect: true }) location: DualComboboxLocation = 'below';
  @Prop() toggleButtonAriaLabelClosed: string = '';
  @Prop() toggleButtonAriaLabelOpen: string = '';
  @Prop() hideIcon: boolean = false;

  @Prop() noDivider: boolean = false;
  @Prop() maxViewableItems: number | null = null;

  @Prop() isLoading: boolean = false;
  @Prop() loadingText: string = 'Loading...';
  @Prop() loaderSize: RadialLoaderSize = 'medium';
  @Prop() loaderLabelPlacement: RadialLabelPlacement = 'inline';
  @Prop() showLoaderLabel: boolean = true;

  @Prop() emptyText: string = 'No results.';
  @Prop() emptyTextSize: InlineMessageSize = 'default';

  @Prop() isErrorLoading: boolean = false;
  @Prop() errorText: string = 'Failed to load items. Please try again.';
  @Prop() errorTextSize: InlineMessageSize = 'default';

  @Event() wdprValueChanged: EventEmitter<{ leadingValue?: string; trailingValue?: string }>;
  @Event() wdprSelectionChange: EventEmitter<{ selectedValue: { id: string; value: string; label: string } | null }>;

  @Listen('wdprSelect')
  handleItemSelect(event: CustomEvent<{ value: string; label: string; selected: boolean; id: string }>) {
    event.stopPropagation();
    const {
      detail: { value, label, selected, id },
    } = event;
    this._updateSelectedValues(value, label, selected, id);

    this._closeDropdown();
  }

  @Watch('leadingValue')
  @Watch('trailingValue')
  handleControlledValueChange() {
    this._applyValue();
  }

  @Watch('_expanded')
  handleExpandedChange(newValue: boolean) {
    if (!newValue) {
      this._removeAriaActivedescendant();
      this._setFocusIndex(null);
    }
  }

  @Watch('maxViewableItems')
  handleMaxViewableItemsChange() {
    requestAnimationFrame(() => {
      this._measureItemHeights();
    });
  }

  @Watch('_selectedValue')
  updateSelectedValues() {
    this._syncSelectionItemsState();
    this._applyFilter();
    this._updateFormValue();
  }

  @Watch('name')
  @Watch('required')
  @Watch('disabled')
  formPropsChanged() {
    this._updateFormValue();
  }

  @Watch('_leadingInputValue')
  @Watch('_trailingInputValue')
  handleInputValueChange() {
    this._handleSearchChange();
  }

  @Listen('click', { target: 'document' })
  handleClickOutside(event: MouseEvent) {
    if (this._expanded && this.el && !event.composedPath().includes(this.el)) {
      this._closeDropdown();
    }
  }

  componentWillLoad() {
    this._listId = `wdpr-dual-combobox-list-${generateRandId()}`;
    this._updateFormValue();
  }

  componentDidLoad() {
    requestAnimationFrame(() => {
      this._initAllItems();
      this._applyValue();
      this._measureItemHeights();
      if (this._listEl) {
        this._slotObserver.observe(this._listEl, { childList: true, subtree: true });
      }
    });

    this._slotObserver = new MutationObserver(mutations => {
      const items = mutations.flatMap(m => Array.from(m.addedNodes)).filter((n): n is HTMLElement => n.nodeType === Node.ELEMENT_NODE);

      if (items.length === 0) return;

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      Promise.all(items.map(el => ('componentOnReady' in el ? (el as any).componentOnReady() : Promise.resolve()))).then(() => {
        this._initAllItems();
        if ((this.leadingValue || this.trailingValue) && this._selectedValue === null) {
          this._applyValue();
        }
        this._measureItemHeights();
      });
    });
  }

  disconnectedCallback() {
    this._slotObserver?.disconnect();
  }

  private _applyValue(): void {
    const allItems = this._getAllListItems();

    if (!this.leadingValue && !this.trailingValue) {
      this._selectedValue = null;
      this._clearInputs();

      return;
    }

    const matchedItem = allItems.find(item => !item.disabled && splitLabel(item.label)[0] === this.leadingValue && splitLabel(item.label)[1] === this.trailingValue);

    if (matchedItem) {
      this._selectedValue = { value: matchedItem.value, label: matchedItem.label, id: matchedItem.id };
      this._setInputsFromLabel(matchedItem.label);
    } else {
      this._selectedValue = null;
      this._leadingInputValue = this.leadingValue;
      this._trailingInputValue = this.trailingValue;
    }
  }

  private _getSelectedFormValue(): string {
    if (!this._selectedValue) return null;

    const { value } = this._selectedValue;

    return value;
  }

  private _updateFormValue() {
    const hasValue = !!this._selectedValue;
    const shouldSubmit = !this.disabled && !!this.name && hasValue;

    this.internals?.setFormValue?.(shouldSubmit ? this._getSelectedFormValue() : null);
    this._updateValidity();
  }

  private _updateValidity() {
    if (this.disabled) {
      this.internals?.setValidity?.({});

      return;
    }

    if (this.required && !this._selectedValue) {
      this.internals?.setValidity?.({ valueMissing: true }, 'An option is required');

      return;
    }

    this.internals?.setValidity?.({});
  }

  private _handleSearchChange() {
    clearTimeout(this._measureDebounceTimer);
    this._measureDebounceTimer = setTimeout(() => {
      this._applyFilter();
      this._focusedIndex = -1;
      requestAnimationFrame(() => this._measureItemHeights());
    }, 100);
  }

  /**
   * Filters items based on both input values by calling hideItem/showItem on each DOM item.
   */
  private _applyFilter() {
    if (this.filterMode === 'manual') return;

    const domItems = this._getAllListItems();

    if (!domItems.length) return;

    const leadingFilter = this._leadingInputValue;
    const trailingFilter = this._trailingInputValue;

    const visibleItems: DualComboboxItemElement[] = [];

    domItems.forEach(item => {
      const matchesLeading = itemMatchesFilter(item, leadingFilter);
      const matchesTrailing = itemMatchesFilter(item, trailingFilter);
      const matches = matchesLeading && matchesTrailing;

      if (matches) {
        item.isHidden = false;
      } else {
        item.isHidden = true;
      }

      if (matches) visibleItems.push(item);
    });

    const groupLastItems = this._groupLastItems();
    const lastVisible = visibleItems[visibleItems.length - 1];

    visibleItems.forEach(async item => {
      const shouldHideDivider = this.noDivider || item === lastVisible || groupLastItems.has(item);
      if (shouldHideDivider) {
        await item.hideDivider();
      } else {
        await item.showDivider();
      }
    });

    const groups = Array.from(this.el.querySelectorAll('wdpr-dual-combobox-group'));
    groups.forEach(async group => {
      const groupItems = Array.from(group.querySelectorAll('[data-dual-combobox-item]')).filter(isDualComboboxItemElement);
      const allHidden = groupItems.every(item => item.isHidden);

      if (allHidden) {
        await group.hideGroup();
      } else {
        await group.showGroup();
      }
    });
  }

  private _updateSelectedValues(value: string, label: string, selected: boolean, id: string) {
    this._selectedValue = selected ? { value, label, id } : null;

    if (selected) {
      this._setInputsFromLabel(label);
    }

    this.wdprSelectionChange.emit({ selectedValue: this._selectedValue });
  }

  private _handleInputClick = () => {
    if (this.disabled) return;
    this._expanded = true;
  };

  private _handleInputFocus = () => {
    if (this.disabled) return;

    this._applyFilter();
  };

  private _handleValueChanged = (event: CustomEvent<{ leadingValue?: string; trailingValue?: string }>) => {
    const { leadingValue, trailingValue } = event.detail;
    event.stopPropagation();

    if (leadingValue !== undefined && leadingValue !== this._leadingInputValue) {
      this._leadingInputValue = leadingValue;
      this._activeInput = 'leading';
      if (!this._expanded) this._expanded = true;
      if (this._selectedValue) {
        this._selectedValue = null;
        this.wdprSelectionChange.emit({ selectedValue: this._selectedValue });
      }
    }

    if (trailingValue !== undefined && trailingValue !== this._trailingInputValue) {
      this._trailingInputValue = trailingValue;
      this._activeInput = 'trailing';
      if (!this._expanded) this._expanded = true;
      if (this._selectedValue) {
        this._selectedValue = null;
        this.wdprSelectionChange.emit({ selectedValue: this._selectedValue });
      }
    }

    this.wdprValueChanged.emit({ leadingValue, trailingValue });
    this._updateFormValue();
  };

  private _syncSelectionItemsState(): void {
    const items = this._getAllListItems();
    items.forEach(item => {
      item.selected = this._selectedValue?.value === item.value && this._selectedValue?.id === item.id;
    });
  }

  private _closeDropdown() {
    this._expanded = false;

    // Reset inputs to match selection state when closing
    if (this._selectedValue) {
      this._setInputsFromLabel(this._selectedValue.label);
    } else {
      this._clearInputs();
    }

    this.wdprValueChanged.emit({ leadingValue: this._leadingInputValue, trailingValue: this._trailingInputValue });
  }

  /**
   * Handles keyboard navigation and accessibility for the dropdown.
   * Supports arrow keys, Enter, Space, Escape, and Tab for navigation and selection.
   * @param ev The keyboard event
   */
  private _handleKeydown = (ev: KeyboardEvent): void => {
    if (this.disabled || this.readonly) return;

    const items = this._getAllListItems();
    if (!items.length) return;

    // Handle Enter and Space for toggle/selection
    if (ev.key === KEYBOARD_KEYS.ENTER || (ev.key === KEYBOARD_KEYS.SPACE && this._focusedIndex >= 0)) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'down');
        this._focusItemAtIndex(startIndex, items);
      } else {
        const focusedItem = items[this._focusedIndex];
        if (focusedItem && !focusedItem.disabled) {
          focusedItem.click();
        }
      }

      return;
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_DOWN) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'down');
        this._focusItemAtIndex(startIndex, items);

        return;
      }

      const nextIndex = findNextEnabledIndex(items, this._focusedIndex, 'down');
      this._focusItemAtIndex(nextIndex, items);
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_UP) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'up');
        this._focusItemAtIndex(startIndex, items);

        return;
      }

      const prevIndex = findNextEnabledIndex(items, this._focusedIndex, 'up');
      this._focusItemAtIndex(prevIndex, items);
    }

    if (ev.key === KEYBOARD_KEYS.ESCAPE) {
      this._closeDropdown();
    }

    if (ev.key === KEYBOARD_KEYS.TAB) {
      this._closeDropdown();
    }
  };

  private _handleIconButtonClick = (event: Event) => {
    event.stopPropagation();

    if (this.disabled || this.readonly) return;

    this._expanded = !this._expanded;
  };

  private _getAllListItems(): DualComboboxItemElement[] {
    if (!this._cachedItems?.length) {
      this._cachedItems = Array.from(this.el?.querySelectorAll('[data-dual-combobox-item]')).filter(isDualComboboxItemElement);
    }

    return this._cachedItems;
  }

  private _invalidateItemsCache(): void {
    this._cachedItems = null;
  }

  private _getAllVisibleListItems(): DualComboboxItemElement[] {
    return this._getAllListItems().filter(item => !item.isHidden);
  }

  private _groupLastItems(): Set<DualComboboxItemElement> {
    const groupElements = Array.from(this.el.querySelectorAll('wdpr-dual-combobox-group'));

    const lastItems: DualComboboxItemElement[] = [];

    for (const group of groupElements) {
      const items = Array.from(group.querySelectorAll('[data-dual-combobox-item]')).filter(isDualComboboxItemElement);

      const lastItem = items[items.length - 1];

      if (lastItem) {
        lastItems.push(lastItem);
      }
    }

    return new Set<DualComboboxItemElement>(lastItems);
  }

  private async _initAllItems(): Promise<void> {
    this._invalidateItemsCache();
    const allItems = this._getAllListItems();

    if (allItems.length === 0) return;
    const lastItem = allItems[allItems.length - 1];

    const groupLastItems = this._groupLastItems();

    for (const item of allItems) {
      if (this.noDivider || item === lastItem || groupLastItems.has(item)) {
        if (typeof item.hideDivider === 'function') {
          await item.hideDivider();
        }
      }
    }

    const preSelected = allItems.find(item => item.selected && !item.disabled);
    if (preSelected) {
      this._selectedValue = { value: preSelected.value, label: preSelected.label, id: preSelected.id };
      this._setInputsFromLabel(preSelected.label);
    } else {
      this._selectedValue = null;
    }
  }

  /**
   * Sets focus to the item at the given index, updates ARIA attributes, and scrolls it into view.
   * @param index The index of the item to focus
   * @param items The array of dropdown items
   */
  private _focusItemAtIndex(index: number, items: DualComboboxItemElement[]): void {
    this._setFocusIndex(index);
    this._updateAriaActivedescendant(items[index]);

    // Scroll the focused item into view
    const focusedItem = items[index];
    if (focusedItem) {
      this._scrollIntoItem(focusedItem);
    }
  }

  private _scrollIntoItem(item: DualComboboxItemElement): void {
    const listbox = this.el?.querySelector('.listbox');
    if (listbox) {
      item.scrollIntoView({ block: 'nearest', inline: 'nearest' });
    }
  }

  private _setFocusIndex(index: number | null): void {
    const items = this._getAllListItems();
    items.forEach((item, i) => {
      item.isFocused = i === index;
    });

    this._focusedIndex = index == null ? -1 : index;
  }

  private _updateAriaActivedescendant(item: DualComboboxItemElement): void {
    this._activeDescendantId = item?.id;
  }

  private _removeAriaActivedescendant(): void {
    this._activeDescendantId = undefined;
  }

  /**
   * Measures the height of the dropdown list and sets the max height for scrollable lists.
   * Calculates based on the number of visible items and their bounding rectangles.
   */
  private _measureItemHeights(): void {
    if (this.maxViewableItems == null || this.maxViewableItems <= 0) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    // As we hide items by setting display: none, we need to filter those out when calculating heights
    const allVisibleListItems: DualComboboxItemElement[] = this._getAllVisibleListItems();

    const listbox = this.el?.querySelector('.listbox');

    if (!listbox || allVisibleListItems.length === 0) {
      this._readyToShow = true;

      return;
    }

    if (allVisibleListItems.length <= this.maxViewableItems) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const targetItem = allVisibleListItems[this.maxViewableItems - 1];
    const wrapperRect = listbox.getBoundingClientRect();
    const itemRect = targetItem.getBoundingClientRect();

    let calculatedHeight = Math.ceil(itemRect.bottom - wrapperRect.top);

    // Add Wrapper Padding (if available)
    const style = window.getComputedStyle(listbox);
    const paddingBottom = parseFloat(style.paddingBottom) || 0;
    calculatedHeight += paddingBottom;

    this._measuredMaxHeight = `${calculatedHeight}px`;
    this._readyToShow = true;
  }

  private _getIconName(): DualComboboxIconNameType {
    return this._expanded ? 'expand-show-less' : 'expand-show-more';
  }

  private _getIconButtonAriaLabel(): string {
    const closedLabel = this.toggleButtonAriaLabelClosed || 'Open list';
    const openLabel = this.toggleButtonAriaLabelOpen || 'Close list';

    return this._expanded ? openLabel : closedLabel;
  }

  private _setInputsFromLabel(label: string) {
    const [leading, trailing] = splitLabel(label);
    this._leadingInputValue = leading;
    this._trailingInputValue = trailing;
  }

  private _clearInputs() {
    this._leadingInputValue = '';
    this._trailingInputValue = '';
  }

  private _renderList(): JSX.Element {
    const isScrollable = this.maxViewableItems != null && this.maxViewableItems > 0;

    return (
      <div ref={el => (this._listEl = el)} class="listbox" role="listbox" id={this._listId} tabindex={isScrollable ? 0 : undefined} aria-label={this.a11yLabel}>
        <slot />
      </div>
    );
  }

  private _renderListWrapper(): JSX.Element {
    const listContainerClasses = this._isListVisible ? 'dual-combobox-list-container-visible' : 'dual-combobox-list-container-invisible';

    return (
      <div class={`dual-combobox-list-container ${listContainerClasses}`} style={{ height: this._measuredMaxHeight }}>
        {this._renderList()}
      </div>
    );
  }

  private _renderStatusMessage(): JSX.Element | null {
    const locationClass = `results-list-${this.location}`;
    const isEmpty = this._getAllListItems().length === 0 || this._getAllVisibleListItems().length === 0;

    if (!this._expanded) return null;
    if (this.isLoading)
      return (
        <div class={`loading-container ${locationClass}`}>
          <wdpr-radial-loader size={this.loaderSize} label={this.loadingText} labelPlacement={this.loaderLabelPlacement} showLabel={this.showLoaderLabel} />
        </div>
      );
    if (isEmpty && !this.isErrorLoading && !this.isLoading)
      return (
        <div class={`empty-container ${locationClass}`}>
          <wdpr-inline-message variant="informational" size={this.emptyTextSize}>{this.emptyText}</wdpr-inline-message>
        </div>
      );
    if (this.isErrorLoading && !this.isLoading)
      return (
        <div class={`error-container ${locationClass}`}>
          <wdpr-inline-message variant="error" size={this.errorTextSize}>{this.errorText}</wdpr-inline-message>
        </div>
      );

    return null;
  }

  private get _isListVisible(): boolean {
    return this._readyToShow && this._expanded && !this.isLoading && this._getAllListItems().length > 0 && !this.isErrorLoading;
  }

  render() {
    return (
      <Host onKeyDown={this._handleKeydown}>
        <div class="dual-combobox-wrapper">
          <wdpr-dual-text-field
            leadingLabel={this.leadingLabel}
            trailingLabel={this.trailingLabel}
            leadingValue={this._leadingInputValue}
            trailingValue={this._trailingInputValue}
            leadingRequirementIndicator={this.leadingRequirementIndicator}
            trailingRequirementIndicator={this.trailingRequirementIndicator}
            disabled={this.disabled}
            error={this.error}
            readonly={this.readonly}
            helperText={this.helperText}
            onWdprInputClick={this._handleInputClick}
            onWdprInputFocus={this._handleInputFocus}
            onWdprValueChanged={this._handleValueChanged}
            a11yRole="combobox"
            a11yHasPopup="listbox"
            a11yAutoComplete="list"
            a11yExpanded={this._expanded ? 'true' : 'false'}
            a11yControls={this._expanded ? this._listId : undefined}
            a11yActiveDescendant={this._activeDescendantId}
          >
            {!this.hideIcon && !this.readonly && (
              <wdpr-icon-button
                slot="trailing-icon-button"
                iconName={this._getIconName()}
                a11yLabel={this._getIconButtonAriaLabel()}
                disabled={this.disabled}
                onClicked={this._handleIconButtonClick}
              />
            )}
          </wdpr-dual-text-field>

          {this._renderListWrapper()}

          {this._renderStatusMessage()}
        </div>
      </Host>
    );
  }
}
